sql:
SELECT AVG(CEIL(file_size_kb)) 
FROM object_files
WHERE file_size_kb > 10;

SELECT programming_language, SUM(file_size_kb) AS total_size_kb
FROM source_files
GROUP BY programming_language;

SELECT AVG(total_size_kb) AS average_total_size_kb
FROM source_files
WHERE programming_language = 'C++' AND last_modified_by = 'jane_doe';

SELECT DISTINCT file_path
FROM source_files
WHERE file_size_kb > 100.00;

SELECT COUNT(DISTINCT source_files.file_id) AS total_files
FROM source_files
INNER JOIN object_files ON source_files.file_id = object_files.source_file_id;

SELECT file_id, file_path, file_type, programming_language, file_size_kb
FROM source_files
WHERE programming_language = 'C' AND file_size_kb < 10;

SELECT file_id, file_path, file_size_kb
FROM source_files
WHERE file_size_kb > (SELECT AVG(file_size_kb) FROM source_files);

SELECT programming_language, file_size_kb
FROM source_files
WHERE file_id = 1;

SELECT AVG(file_size_kb) AS average_size 
FROM source_files 
WHERE file_id IN (SELECT source_file_id FROM object_files);

SELECT source_file_id, COUNT(*) as num_object_files
FROM object_files
GROUP BY source_file_id;

SELECT DISTINCT sf.file_id, sf.programming_language
FROM source_files sf
JOIN file_dependencies fd ON sf.file_id = fd.source_file_id;

SELECT * 
FROM source_files 
WHERE file_size_kb = total_size_kb;

SELECT programming_language, COUNT(DISTINCT project_id) AS project_count
FROM source_files
GROUP BY programming_language;
